from outlines.prompts import prompt, register_filter, unregister_filter

@prompt
def basic(text):
    '''{{ text }}'''

print(repr(basic('hello')))

@prompt(filters={'reverse': lambda s: s[::-1]})
def reverse_prompt(text):
    '''{{ text | reverse }}'''

print(repr(reverse_prompt('hello')))

register_filter('shout', lambda s: s.upper() + '!')

@prompt
def shout_prompt(text):
    '''{{ text | shout }}'''

print(repr(shout_prompt('hi')))
unregister_filter('shout')

from outlines.prompts import Prompt
p = Prompt.from_str('{{ text | reverse }}', filters={'reverse': lambda s: s[::-1]})
print(repr(p(text='world')))
"

